import { Link } from 'react-router-dom';

function LeadTable({
  leads = [],
  onEdit,
  onDelete
}) {
  if (
    !Array.isArray(leads) ||
    leads.length === 0
  ) {
    return (
      <p className="empty-msg">
        No leads found.
      </p>
    );
  }

  return (
    <div className="table-wrapper">
      <table className="lead-table">
        <thead>
          <tr>
            <th>Name</th>

            <th>Country</th>

            <th>Course</th>

            <th>Status</th>

            <th>Priority</th>

            <th>
              Counselor
            </th>

            <th>Actions</th>
          </tr>
        </thead>

        <tbody>
          {leads.map((lead) => (
            <tr key={lead._id}>
              <td>
                <Link
                  className="lead-link"
                  to={`/leads/${lead._id}`}
                >
                  {lead.fullName}
                </Link>
              </td>

              <td>
                {lead.country}
              </td>

              <td>
                {
                  lead.courseInterested
                }
              </td>

              <td>
                <span
                  className={`badge badge-${(
                    lead.leadStatus ||
                    'new'
                  )
                    .replace(
                      /\s+/g,
                      '-'
                    )
                    .toLowerCase()}`}
                >
                  {lead.leadStatus}
                </span>
              </td>

              <td>
                {lead.priority}
              </td>

              <td>
                {lead.assignedCounselor ||
                  'Unassigned'}
              </td>

              <td className="actions">
                <button
                  className="btn-edit"
                  onClick={() =>
                    onEdit(lead)
                  }
                >
                  Edit
                </button>

                <button
                  className="btn-delete"
                  onClick={() =>
                    onDelete(
                      lead._id
                    )
                  }
                >
                  Delete
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default LeadTable;
